#include<bits/stdc++.h>
using namespace std;

bool b[10000001];
unsigned long long cnt = 0;

int main() {
	unsigned  long s, n;
	string a;
	cin >> n >> s >> a;
	for (int i = 0; i < n; i++) {
		if (a[i] == 'U') {
			if (cnt == 0) {
				if(s!=1){
				    s/=2;
				}
			} else {
				cnt--;
			}
		} else if (a[i] == 'R') {
			b[cnt++] = 1;

		} else {
			b[cnt++] = 0;
		}
	}
	for (int i = 0; i < cnt; i++) {
		if (b[i] == 1) {
			s = s * 2 + 1; 
		}else{
			s *= 2; 
		}
	}cout << s; 
	return 0;
}
